  (1819, 'Delta Gestion XIII', 3, 321, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 180, '2026-03-06', 1, '1328', 'Superar la rentabilidad de un plazo fijo en dólares de 30 días, mediante una estrategia de renta fija corto plazo argentina en dólares, con inversión en bonos corporativos y soberanos, una duration objetivo de 6 meses y la posibilidad de invertir hasta 25% de la cartera en Treasury Bills para la gestión de liquidez y volatilidad', 1),
  (420, 'Delta Internacional', 2, 321, 65, 'Renta Variable', 'Global', 'Largo Plazo', NULL, 1, '2017-09-14', 1, '532', 'El fondo tendrá como objetivo la conformación y administración de una cartera diversificada de inversiones en instrumentos financieros y valores negociables de renta variable y/o fija emitidos principalmente por emisores cuya actividad económica preponderante o emisión se vincule con países internacionales.', 1),
  (375, 'Delta Latinoamerica', 2, 321, 65, 'Renta Variable', 'Latinoamerica', 'Largo Plazo', NULL, 1, '2017-09-14', 1, '504', NULL, 1),
  (408, 'Delta Moneda', 3, 321, 65, 'Renta Fija', 'Argentina', 'Flexible', NULL, 1, '2017-09-14', 1, '534', 'Delta Moneda es un fondo de renta fija que busca ofrecer un desempeño comparable a la evolución del tipo de cambio del dólar en el mediano plazo.', 1),
  (466, 'Delta Multimercado I', 5, 321, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2017-09-14', 1, '607', 'El fondo tiene como objetivo de inversión obtener rentabilidades absolutas positivas en el mediano/ largo plazo.', 1),
  (1264, 'Delta Multimercado II', 3, 321, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2021-08-05', 1, '998', 'Sin datos', 1),
  (858, 'Delta Patrimonio I', 3, 321, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2019-01-04', 1, '996', 'Sin datos', 1),
  (614, 'Delta Performance', 11, 321, 65, 'Renta Fija', 'Argentina', 'Flexible', NULL, 1, '2017-04-06', 1, '748', 'Delta Performance tiene como objetivo la preservación del capital invirtiendo en instrumentos de renta fija local en pesos (tanto a tasa fija como variable) de corto plazo con moderada volatilidad.', 0),
  (394, 'Delta Pesos', 4, 321, 65, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 1, '2006-07-03', 1, '536', 'Delta Pesos es un fondo de Mercado de Dinero que tiene como objetivo de inversión maximizar los saldos transitorios de caja de corto plazo, manteniendo altos niveles de liquidez y estricto control de riesgo crediticio.', 0),
  (402, 'Delta Recursos Naturales', 2, 321, 65, 'Renta Variable', 'Argentina', 'Largo Plazo', NULL, 1, '2017-09-14', 1, '535', 'El objetivo del Fondo es invertir de manera diversificada principalmente en empresas locales pertenecientes a sectores de recursos naturales. Como complemento al análisis fundamental (criterio principal de inversión), se buscarán oportunidades de valor relativo intersectoriales en la medida que la existencia de oportunidades de arbitraje así lo justifiquen.', 1),
  (369, 'Delta Renta', 3, 321, 65, 'Renta Fija', 'Argentina', 'Flexible', NULL, 1, '2017-09-14', 1, '503', 'El estilo de gestión del fondo Delta Renta es activo, basado en el análisis macroeconómico, buscando oportunidades de inversión en todas las curvas de renta fija argentina (fija en pesos, Badlar, Cer, Dólar, Dólar Linked, etc.).', 1),
  (709, 'Delta Renta Dolares', 3, 321, 65, 'Renta Fija', 'Argentina', 'Flexible', NULL, 2, '2017-09-14', 1, '849', NULL, 2),
