  (419, 'Delta Select', 2, 321, 65, 'Renta Variable', 'Global', 'Largo Plazo', NULL, 1, '2017-09-14', 1, '531', 'Delta Select tiene como objetivo invertir en acciones de compañías argentinas, buscando lograr rentabilidades superiores a su índice de referencia (Merval Argentina -M.AR-).', 1),
  (1304, 'Delta Sustentable ASG', 10, 321, 65, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2022-01-28', 1, '1232', 'Invertir en activos ASG', 1),
  (273, 'Desarrollo Argentino I FCI Abierto para el Fin. de la Infra. y la Econ. Real', 8, 21, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2017-09-06', 1, '352', 'El fondo tiene como objetivo la apreciación del capital mediante la inversión en instrumentos financieros y valores negociables de renta variable y fija destinados al financiamiento de proyectos productivos de economías regionales e infraestructura de la República Argentina.', 2),
  (427, 'Desarrollo Argentino II FCI Abierto para el Fin. de la Infra. y la Econ. Real', 8, 21, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2015-09-06', 1, '565', 'El fondo tiene como objetivo la apreciación del capital mediante la inversión en instrumentos financieros y valores negociables de renta variable y fija destinados al financiamiento de proyectos productivos de economías regionales e infraestructura de la República Argentina.', 2),
