  (435, 'FBA Bonos Globales', 3, 29, 79, 'Renta Fija', 'Global', 'Largo Plazo', NULL, 1, '2017-10-26', 1, '556', 'Es un fondo que invierte en deuda pública y privada latinoamericana, maximizando el rendimiento tanto por valorización como por renta', 3),
