  (512, 'Gainvest Infraestructura FCI Abierto', 8, 311, 115, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2017-09-05', 1, '649', 'El fondo tiene como objetivo invertir en instrumentos dedicados a la financiación de proyectos productivos públicos y privados. Es un fondo elegible para las inversiones inciso "K" de las Cías. de Seguros, según comunicación SSN 3621 de junio de 2013.', 1),
  (1650, 'Gainvest Performance', 5, 311, 115, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 2, '2025-05-08', 1, '1666', 'Sin datos', 3),
  (1649, 'Gainvest Performance II', 5, 311, 115, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 2, '2025-05-08', 1, '1667', 'Sin datos', 1),
  (638, 'Gainvest Pesos', 4, 311, 115, 'Plazo Fijo', 'Argentina', 'Mediano Plazo', NULL, 1, '2015-10-01', 1, '784', 'El fondo Gainvest Pesos es un fondo categoría de Dinero cuyo principal objetivo es otorgar liquidez a los inversores a través de inversiones de muy bajo riesgo de mercado. Las principales inversiones de este fondo se realizan en productos de origen bancario , tales como cuentas remuneradas.', 0),
  (465, 'Gainvest PYMEs', 6, 311, 115, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2017-09-05', 1, '613', 'El fondo tiene como objetivo maximizar el rendimiento invirtiendo en instrumentos de renta fija y variable destinados a la financiación de Pymes. Es un fondo elegible para las inversiones inciso “L” de las Cías. de Seguros.', 1),
  (511, 'Gainvest Regional', 3, 311, 115, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2011-11-04', 1, '650', 'El fondo invierte principalmente en una cartera diversificada de valores negociables deuda pública provincial y municipal . El plazo de permanencia recomendado es 30 días.', 1),
  (353, 'Gainvest Renta Fija', 3, 311, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2004-09-29', 1, '475', 'El Fondo invierte la mayor parte de su patrimonio en Lebacs, acompañando de esta manera la política de tasas del BCRA.', 1),
  (409, 'Gainvest Renta Fija Dolares', 3, 311, 115, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 2, '2017-09-05', 1, '551', NULL, 1),
  (487, 'Gainvest Renta Fija Plus', 3, 311, 115, 'Renta Fija', 'Argentina', 'Largo Plazo', NULL, 1, '2017-09-05', 1, '622', 'El fondo invierte en Títulos Públicos Nacionales. Actualmente la estrategia de inversión del fondo es posicionarse en la parte media de la curva de dólares. El fondo es de elevada volatilidad. Se recomienda una permanencia mínima de 6 meses', 1),
  (544, 'Gainvest Renta Fija Proteccion Plus', 3, 311, 115, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-05', 1, '678', NULL, 1),
  (1315, 'Gainvest Renta Mixta Sustentable FCI ASG', 10, 311, 65, 'Renta Variable', 'Argentina', 'Mediano Plazo', NULL, 1, '2022-05-09', 1, '1262', 'El fondo tiene como objetivo invertir en valores negociables ASG.', 1),
  (510, 'Gainvest Renta Variable', 2, 311, 115, 'Renta Variable', 'Argentina', 'Flexible', NULL, 1, '2017-09-05', 1, '651', 'El fondo tiene como objetivo de inversión adquirir una cartera diversificada de acciones que componen el panel Merval. Es un fondo de alta volatilidad con una permanencia mínima aconsejada de 6 meses.', 1),
  (615, 'Galileo Acciones', 2, 1, 115, 'Renta Variable', 'Argentina', 'Largo Plazo', NULL, 1, '2015-06-01', 1, '763', 'El Fondo tiene como objetivo capturar la apreciación del capital a largo plazo invirtiendo en instrumentos de renta variable.', 1),
  (489, 'Galileo Ahorro', 3, 1, 115, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2011-05-20', 1, '627', 'El fondo tiene como objetivo capturar un rendimiento superior a la tasa de interés BADLAR a través de una cartera de activos de renta fija de corto plazo con baja volatilidad.', 1),
  (616, 'Galileo Ahorro Plus', 3, 1, 115, 'Renta Fija', 'Argentina', 'Largo Plazo', NULL, 1, '2015-06-01', 1, '765', 'El Fondo tiene como objetivo capturar un rendimiento superior a la tasa de interés BADLAR a través de una cartera de activos de renta fija, que no sean instrumentos emitidos por BCRA, de corto plazo con baja volatilidad.', 1),
  (446, 'Galileo Argentina', 7, 1, 115, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2008-09-02', 1, '581', 'El fondo tiene por objetivo obtener apreciación de capital mediante un portafolio diversificado de Bonos Provinciales para captar un rendimiento superior al de los bonos del gobierno nacional a través del manejo activo de la cartera.', 1),
  (748, 'Galileo Estrategia', 3, 1, 115, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-06-09', 1, '958', 'El fondo tiene como objetivo la preservación del capital invirtiendo en instrumentos de renta fija local en pesos de corto y mediano plazo.', 1),
  (349, 'Galileo Event Driven', 7, 1, 115, 'Renta Mixta', 'Latinoamerica', 'Largo Plazo', NULL, 2, '2004-07-13', 1, '470', 'El Fondo tiene como objetivo alcanzar un rendimiento superior al que ofrece una cartera indexada de bonos latinoamericanos, a partir de una selección exhaustiva de créditos que permita añadir apreciación de capital al ingreso corriente de la cartera, a través de un abanico diversificado de bonos principalmente denominados en dólares estadounidenses, emitidos por empresas y gobiernos de América Latina.', 2),
  (490, 'Galileo FCI Abierto Pymes', 6, 1, 115, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2011-05-23', 1, '626', 'El fondo tiene como objetivo maximizar el rendimiento invirtiendo en instrumentos de renta fija y renta variable del segmento PYME.', 1)
